import { MemoryRouter } from 'react-router-dom';
import { Lifeos } from "./lifeos.js";
    
export const LifeosBasic = () => {
  return (
    <MemoryRouter>
      <Lifeos />
    </MemoryRouter>
  );
}

import React from 'react';
import { Routes, Route } from 'react-router-dom';
import { MobileShell } from './src/components/mobile-shell.js';
import { DashboardPage } from './src/pages/dashboard-page.js';
import { ServicesPage } from './src/pages/services-page.js';
import { RenewalsPage } from './src/pages/renewals-page.js';
import { AnalyticsPage } from './src/pages/analytics-page.js';
import { SettingsPage } from './src/pages/settings-page.js';
import { AddServicePage } from './src/pages/add-service-page.js';
import { ServiceDetailPage } from './src/pages/service-detail-page.js';
import { EditServicePage } from './src/pages/edit-service-page.js';
import { ExpensesPage } from './src/pages/expenses-page.js';
import { AuthPage } from './src/pages/auth-page.js';
import styles from './src/styles/global.module.css';
import './src/styles/reset.module.css';

/**
 * Root LifeOS component: applies the global theme shell and routes between
 * the five main screens plus add/detail flows inside the mobile frame.
 *
 * @returns The routed application.
 */
export function Lifeos(): React.JSX.Element {
  return (
    <div className={styles.app}>
      <MobileShell>
        <Routes>
          <Route path="/" element={<DashboardPage />} />
          <Route path="/services" element={<ServicesPage />} />
          <Route path="/renewals" element={<RenewalsPage />} />
          <Route path="/analytics" element={<AnalyticsPage />} />
          <Route path="/expenses" element={<ExpensesPage />} />
          <Route path="/settings" element={<SettingsPage />} />
          <Route path="/add" element={<AddServicePage />} />
          <Route path="/service/:id" element={<ServiceDetailPage />} />
          <Route path="/edit/:id" element={<EditServicePage />} />
          <Route path="/auth" element={<AuthPage />} />
        </Routes>
      </MobileShell>
    </div>
  );
}

import ReactDOMServer from "react-dom/server";
import { StaticRouter } from "react-router";
import { Lifeos } from "./lifeos.js";

interface IRenderProps {
  path: string;
}
    
export const render = async ({ path }: IRenderProps) => {
  return ReactDOMServer.renderToString(
    <StaticRouter location={path}>
      <Lifeos />
    </StaticRouter>
  );
};

/**
 * implement loadScripts() to inject scripts to the head
 * during SSR.
 */
// export const loadScripts = async () => {
//   return '<script></script>';
// }

.header {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 22px 4px 8px;
}
.menu {
  width: 46px;
  height: 46px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.12);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  cursor: pointer;
  flex-shrink: 0;
}
.menu span {
  display: block;
  width: 18px;
  height: 2px;
  border-radius: 2px;
  background: #fff;
}
.menu span:nth-child(2) {
  width: 12px;
}
.greeting {
  flex: 1;
  text-align: right;
}
.hi {
  margin: 0;
  font-size: 18px;
  font-weight: 800;
  color: #fff;
}
.wave {
  display: inline-block;
}
.sub {
  margin: 2px 0 0;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.55);
}
.avatarWrap {
  position: relative;
  flex-shrink: 0;
}
.avatar {
  position: relative;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  border: none;
  background: linear-gradient(145deg, #a855f7, #4f46e5);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 800;
  color: #fff;
  font-size: 18px;
  flex-shrink: 0;
  cursor: pointer;
  font-family: inherit;
  box-shadow: 0 8px 20px rgba(124, 58, 237, 0.5);
  transition: transform 0.18s;
}
.avatar:active {
  transform: scale(0.92);
}
.dot {
  position: absolute;
  top: 0;
  left: 2px;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: #63e8ff;
  border: 2px solid #020b38;
}

import React, { useState } from 'react';
import { useSettings } from '../store/use-settings.js';
import { UserAvatar } from './user-avatar.js';
import { SidebarDrawer } from './sidebar-drawer.js';
import { QuickActionsSheet } from './quick-actions-sheet.js';
import styles from './app-header.module.css';

/**
 * Top header with a hamburger menu that opens the sidebar drawer, a Persian
 * greeting, and a user avatar that opens the Quick Actions bottom sheet.
 *
 * @returns The home screen header.
 */
export function AppHeader(): React.JSX.Element {
  const userName = useSettings((s) => s.userName);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [sheetOpen, setSheetOpen] = useState(false);

  return (
    <>
      <header className={styles.header}>
        <button
          className={styles.menu}
          type="button"
          aria-label="منو"
          onClick={() => setDrawerOpen(true)}
        >
          <span />
          <span />
          <span />
        </button>
        <div className={styles.greeting}>
          <p className={styles.hi}>
            سلام، {userName} <span className={styles.wave}>👋</span>
          </p>
          <p className={styles.sub}>خوش آمدی به LifeOS</p>
        </div>
        <UserAvatar
          size={48}
          onClick={() => setSheetOpen(true)}
          ariaLabel="عملیات سریع"
          ariaExpanded={sheetOpen}
        />
      </header>

      <SidebarDrawer open={drawerOpen} onClose={() => setDrawerOpen(false)} />
      <QuickActionsSheet open={sheetOpen} onClose={() => setSheetOpen(false)} />
    </>
  );
}

@keyframes popIn {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.popover {
  position: absolute;
  top: calc(100% + 10px);
  left: 0;
  width: 260px;
  padding: 16px;
  border-radius: 24px;
  background: rgba(15, 23, 42, 0.78);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.35);
  z-index: 100;
  transform-origin: top left;
  animation: popIn 180ms ease-out;
}

.header {
  display: flex;
  align-items: center;
  gap: 12px;
  text-align: right;
}
.avatar {
  width: 48px;
  height: 48px;
  border-radius: 50%;
  background: linear-gradient(145deg, #a855f7, #4f46e5);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 800;
  font-size: 19px;
  color: #fff;
  flex-shrink: 0;
  box-shadow: 0 8px 18px rgba(124, 58, 237, 0.5);
}
.identity {
  flex: 1;
  min-width: 0;
}
.editBtn {
  width: 34px;
  height: 34px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.06);
  cursor: pointer;
  font-size: 14px;
  flex-shrink: 0;
  transition: background 0.18s;
}
.editBtn:hover {
  background: rgba(99, 232, 255, 0.14);
}
.editProfile {
  width: 100%;
  margin-top: 14px;
  padding: 11px;
  border-radius: 14px;
  border: 1px solid rgba(168, 85, 247, 0.3);
  background: rgba(168, 85, 247, 0.12);
  color: #d8b4fe;
  font-family: inherit;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  transition: background 0.18s;
}
.editProfile:hover {
  background: rgba(168, 85, 247, 0.2);
}
.editPanel {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 14px;
}
.editInput {
  width: 100%;
  padding: 11px 14px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.06);
  color: #fff;
  font-family: inherit;
  font-size: 13.5px;
  outline: none;
}
.editInput:focus {
  border-color: #63e8ff;
}
.editActions {
  display: flex;
  gap: 10px;
}
.cancelBtn,
.saveBtn {
  flex: 1;
  padding: 11px;
  border-radius: 14px;
  font-family: inherit;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  border: none;
}
.cancelBtn {
  background: rgba(255, 255, 255, 0.07);
  color: rgba(255, 255, 255, 0.7);
  border: 1px solid rgba(255, 255, 255, 0.1);
}
.saveBtn {
  background: linear-gradient(145deg, #2fd0ff, #63e8ff);
  color: #020b38;
}
.name {
  margin: 0;
  font-size: 16px;
  font-weight: 800;
  color: #fff;
}
.subtitle {
  margin: 2px 0 0;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.5);
}

.changePhoto {
  width: 100%;
  margin-top: 14px;
  padding: 11px;
  border-radius: 14px;
  border: 1px solid rgba(99, 232, 255, 0.25);
  background: rgba(99, 232, 255, 0.1);
  color: #63e8ff;
  font-family: inherit;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  transition: background 0.18s;
}
.changePhoto:hover {
  background: rgba(99, 232, 255, 0.18);
}
.stats {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-top: 14px;
}
.stat {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  padding: 10px 6px;
  border-radius: 14px;
  background: rgba(99, 232, 255, 0.07);
}
.statValue {
  font-size: 18px;
  font-weight: 800;
  color: #63e8ff;
}
.statLabel {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.6);
}
.statDivider {
  width: 1px;
  height: 30px;
  background: rgba(255, 255, 255, 0.08);
}

.divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.08);
  margin: 14px 0;
}

.group {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.row {
  display: flex;
  align-items: center;
  gap: 12px;
  height: 48px;
  padding: 0 10px;
  border: none;
  border-radius: 14px;
  background: transparent;
  cursor: pointer;
  font-family: inherit;
  text-align: right;
  transition: background 0.18s, transform 0.18s;
}
.row:hover {
  background: rgba(99, 232, 255, 0.12);
  transform: translateX(-2px);
}
.rowIcon {
  font-size: 17px;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}
.rowLabel {
  flex: 1;
  font-size: 13.5px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.9);
}
.chevron {
  display: flex;
  color: rgba(255, 255, 255, 0.35);
  flex-shrink: 0;
}

.footer {
  margin: 14px 0 0;
  text-align: center;
  font-size: 11px;
  color: rgba(255, 255, 255, 0.35);
}

import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useServices } from '../store/use-services.js';
import { useSettings } from '../store/use-settings.js';
import { daysUntil } from '../lib/dates.js';
import { toFaDigits } from '../lib/format.js';
import { resizeImageToDataUrl, ACCEPTED_IMAGE_TYPES } from '../lib/image.js';
import { UserAvatar } from './user-avatar.js';
import styles from './avatar-popover.module.css';

/**
 * Props for {@link AvatarPopover}.
 */
export interface AvatarPopoverProps {
  /** Whether the popover is open. */
  open: boolean;
  /** Called when the popover requests to close. */
  onClose: () => void;
}

/** A quick-action menu row definition. */
interface ActionItem {
  icon: string;
  label: string;
  to: string;
}

const CHEVRON = (
  <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <path d="m15 6-6 6 6 6" />
  </svg>
);

const QUICK_ACTIONS: ActionItem[] = [
  { icon: '➕', label: 'افزودن سرویس', to: '/add' },
  { icon: '🌐', label: 'افزودن دامنه', to: '/add' },
  { icon: '📅', label: 'افزودن تمدید', to: '/renewals' },
  { icon: '✅', label: 'افزودن وظیفه', to: '/add' },
  { icon: '💰', label: 'ثبت هزینه', to: '/add' },
];

const SECONDARY_ACTIONS: ActionItem[] = [
  { icon: '⚙️', label: 'تنظیمات', to: '/settings' },
  { icon: '📤', label: 'خروجی گرفتن از اطلاعات', to: '/settings' },
  { icon: '💾', label: 'پشتیبان‌گیری', to: '/settings' },
];

/**
 * A premium glassmorphism profile popover anchored beneath the avatar. Shows
 * the user header with live stats, quick actions, secondary actions, and a
 * footer. Closes on outside click, ESC, or item selection.
 *
 * @param props - Open state and close handler.
 * @returns The avatar popover, or null when closed.
 */
export function AvatarPopover({ open, onClose }: AvatarPopoverProps): React.JSX.Element | null {
  const navigate = useNavigate();
  const userName = useSettings((s) => s.userName);
  const userEmail = useSettings((s) => s.userEmail);
  const setUserName = useSettings((s) => s.setUserName);
  const setUserEmail = useSettings((s) => s.setUserEmail);
  const setAvatarImage = useSettings((s) => s.setAvatarImage);
  const services = useServices((s) => s.services);
  const ref = useRef<HTMLDivElement>(null);
  const fileRef = useRef<HTMLInputElement>(null);
  const [editing, setEditing] = useState(false);
  const [nameDraft, setNameDraft] = useState(userName);
  const [emailDraft, setEmailDraft] = useState(userEmail ?? '');

  const activeCount = services.filter((s) => s.active).length;
  const upcomingCount = services.filter((s) => {
    const d = daysUntil(s.nextRenewal);
    return s.active && d >= 0 && d <= 14;
  }).length;

  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    const onClick = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) onClose();
    };
    document.addEventListener('keydown', onKey);
    // Defer so the opening click does not immediately close it.
    const t = setTimeout(() => document.addEventListener('mousedown', onClick), 0);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.removeEventListener('mousedown', onClick);
      clearTimeout(t);
    };
  }, [open, onClose]);

  /** Enters edit mode, seeding the drafts from current values. */
  const startEdit = () => {
    setNameDraft(userName);
    setEmailDraft(userEmail ?? '');
    setEditing(true);
  };

  /** Saves profile drafts to the store and exits edit mode. */
  const saveEdit = () => {
    if (nameDraft.trim()) setUserName(nameDraft.trim());
    setUserEmail(emailDraft.trim());
    setEditing(false);
  };

  if (!open) return null;

  /** Navigates to a target and closes the popover. */
  const go = (to: string) => {
    navigate(to);
    onClose();
  };

  /** Reads the selected image, resizes it, and persists it to LocalStorage. */
  const onPickImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    e.target.value = '';
    if (!file || !ACCEPTED_IMAGE_TYPES.includes(file.type)) return;
    try {
      const dataUrl = await resizeImageToDataUrl(file, 256);
      setAvatarImage(dataUrl);
    } catch {
      // ignore unreadable images
    }
  };

  const renderRow = (item: ActionItem) => (
    <button key={item.label} type="button" className={styles.row} onClick={() => go(item.to)}>
      <span className={styles.rowIcon}>{item.icon}</span>
      <span className={styles.rowLabel}>{item.label}</span>
      <span className={styles.chevron}>{CHEVRON}</span>
    </button>
  );

  return (
    <div ref={ref} className={styles.popover} role="menu">
      <div className={styles.header}>
        <UserAvatar size={52} showStatus={false} />
        <div className={styles.identity}>
          <p className={styles.name}>{userName}</p>
          <p className={styles.subtitle}>{userEmail || 'LifeOS User'}</p>
        </div>
        {!editing ? (
          <button
            type="button"
            className={styles.editBtn}
            onClick={startEdit}
            aria-label="ویرایش پروفایل"
          >
            ✏️
          </button>
        ) : null}
      </div>

      {editing ? (
        <div className={styles.editPanel}>
          <input
            className={styles.editInput}
            value={nameDraft}
            onChange={(e) => setNameDraft(e.target.value)}
            placeholder="نام شما"
          />
          <input
            className={styles.editInput}
            value={emailDraft}
            onChange={(e) => setEmailDraft(e.target.value)}
            placeholder="ایمیل (اختیاری)"
            inputMode="email"
          />
          <button
            type="button"
            className={styles.changePhoto}
            onClick={() => fileRef.current?.click()}
          >
            📷 تغییر تصویر پروفایل
          </button>
          <div className={styles.editActions}>
            <button type="button" className={styles.cancelBtn} onClick={() => setEditing(false)}>
              انصراف
            </button>
            <button type="button" className={styles.saveBtn} onClick={saveEdit}>
              ذخیره
            </button>
          </div>
        </div>
      ) : (
        <button
          type="button"
          className={styles.editProfile}
          onClick={startEdit}
        >
          👤 ویرایش پروفایل
        </button>
      )}
      <input
        ref={fileRef}
        type="file"
        accept=".jpg,.jpeg,.png,.webp,image/jpeg,image/png,image/webp"
        onChange={onPickImage}
        style={{ display: 'none' }}
      />

      <div className={styles.stats}>
        <div className={styles.stat}>
          <span className={styles.statValue}>{toFaDigits(activeCount)}</span>
          <span className={styles.statLabel}>سرویس فعال</span>
        </div>
        <div className={styles.statDivider} />
        <div className={styles.stat}>
          <span className={styles.statValue}>{toFaDigits(upcomingCount)}</span>
          <span className={styles.statLabel}>تمدید نزدیک</span>
        </div>
      </div>

      <div className={styles.divider} />

      <div className={styles.group}>{QUICK_ACTIONS.map(renderRow)}</div>

      <div className={styles.divider} />

      <div className={styles.group}>{SECONDARY_ACTIONS.map(renderRow)}</div>

      <p className={styles.footer}>LifeOS v1.0</p>
    </div>
  );
}

.nav {
  position: absolute;
  bottom: 12px;
  left: 50%;
  transform: translateX(-50%);
  width: calc(100% - 24px);
  height: 70px;
  z-index: 50;
  pointer-events: none;
}
.bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  filter: drop-shadow(0 10px 20px rgba(62, 208, 240, 0.3));
}
.row {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  padding-top: 4px;
  pointer-events: auto;
}
.side {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: space-around;
  height: 100%;
}
.gap {
  width: 72px;
  flex-shrink: 0;
}
.tab {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  background: none;
  border: none;
  cursor: pointer;
  font-family: inherit;
  color: rgba(255, 255, 255, 0.9);
  padding: 3px 6px;
  border-radius: 14px;
  transition: transform 0.2s, opacity 0.2s;
  opacity: 0.72;
}
.tab.active {
  opacity: 1;
  transform: translateY(-2px);
}
.icon {
  display: flex;
}
.label {
  font-size: 10px;
  font-weight: 700;
}
.fab {
  position: absolute;
  top: -14px;
  left: 50%;
  transform: translateX(-50%);
  width: 54px;
  height: 54px;
  border-radius: 50%;
  background: #fff;
  border: none;
  color: #0a1230;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  pointer-events: auto;
