import type { Service, ServiceCategory } from '../types/index.js';
import { monthlyCost } from './dates.js';
import { CATEGORY_META } from '../data/categories.js';

/** Aggregated spending grouped by category. */
export interface CategorySlice {
  category: ServiceCategory;
  label: string;
  color: string;
  value: number;
}

/**
 * Groups monthly spend by category for the breakdown chart.
 *
 * @param services - Services to aggregate.
 * @returns Non-empty category slices sorted by value descending.
 */
export function spendByCategory(services: Service[]): CategorySlice[] {
  const map = new Map<ServiceCategory, number>();
  services
    .filter((s) => s.active)
    .forEach((s) => {
      map.set(s.category, (map.get(s.category) ?? 0) + monthlyCost(s));
    });
  return Array.from(map.entries())
    .map(([category, value]) => ({
      category,
      label: CATEGORY_META[category].label,
      color: CATEGORY_META[category].color,
      value: Math.round(value),
    }))
    .sort((a, b) => b.value - a.value);
}

/** A single point on the monthly spending trend line. */
export interface MonthPoint {
  month: string;
  value: number;
}

const FA_MONTHS = [
  'فروردین',
  'اردیبهشت',
  'خرداد',
  'تیر',
  'مرداد',
  'شهریور',
];

/**
 * Builds a simulated 6-month spending trend based on the current monthly base.
 *
 * @param services - Services to derive the base spend from.
 * @returns Six trend points ending at the current month.
 */
export function spendTrend(services: Service[]): MonthPoint[] {
  const base = services
    .filter((s) => s.active)
    .reduce((sum, s) => sum + monthlyCost(s), 0);
  const factors = [0.74, 0.81, 0.88, 0.92, 0.85, 1];
  return FA_MONTHS.map((month, i) => ({
    month,
    value: Math.round(base * factors[i]),
  }));
}

/**
 * Returns the most expensive services by monthly cost.
 *
 * @param services - Services to rank.
 * @param limit - Maximum number of results.
 * @returns Ranked list with computed monthly cost.
 */
export function topServices(
  services: Service[],
  limit = 5
): Array<{ service: Service; monthly: number }> {
  return services
    .filter((s) => s.active)
    .map((s) => ({ service: s, monthly: Math.round(monthlyCost(s)) }))
    .sort((a, b) => b.monthly - a.monthly)
    .slice(0, limit);
}

import type { Service } from '../types/index.js';
import { toFaDigits } from './format.js';

/**
 * Number of whole days from today until the given ISO date.
 *
 * @param iso - ISO date string.
 * @returns Days remaining (negative if in the past).
 */
export function daysUntil(iso: string): number {
  const target = new Date(iso);
  target.setHours(0, 0, 0, 0);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const diff = target.getTime() - today.getTime();
  return Math.round(diff / (1000 * 60 * 60 * 24));
}

/**
 * Persian relative label for a renewal date.
 *
 * @param iso - ISO date string.
 * @returns Label such as "امروز" or "۳ روز دیگر".
 */
export function renewalLabel(iso: string): string {
  const d = daysUntil(iso);
  if (d < 0) return `${toFaDigits(Math.abs(d))} روز پیش`;
  if (d === 0) return 'امروز';
  if (d === 1) return 'فردا';
  return `${toFaDigits(d)} روز دیگر`;
}

/**
 * Normalizes a service price to an equivalent monthly cost in Toman.
 *
 * @param service - The service to evaluate.
 * @returns Monthly-equivalent cost.
 */
const USD_RATE = 60_000;

export function monthlyCost(service: Service): number {
  const inIRT = service.priceCurrency === 'USD' ? service.price * USD_RATE : service.price;
  return service.billingCycle === 'yearly' ? inIRT / 12 : inIRT;
}

export function yearlyCost(service: Service): number {
  const inIRT = service.priceCurrency === 'USD' ? service.price * USD_RATE : service.price;
  return service.billingCycle === 'yearly' ? inIRT : inIRT * 12;
}

export function todayJalali(): string {
  try {
    return new Intl.DateTimeFormat('fa-IR-u-ca-persian', { year: 'numeric', month: 'long', day: 'numeric' }).format(new Date());
  } catch {
    return new Intl.DateTimeFormat('fa-IR', { year: 'numeric', month: 'long', day: 'numeric' }).format(new Date());
  }
}

/**
 * Formats an ISO date as a Persian date string (Gregorian month names omitted,
 * uses localized numeric format).
 *
 * @param iso - ISO date string.
 * @returns Localized date string.
 */
export function formatDate(iso: string): string {
  try {
    return new Intl.DateTimeFormat('fa-IR', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    }).format(new Date(iso));
  } catch {
    return toFaDigits(new Date(iso).toLocaleDateString());
  }
}

import type { Currency } from '../types/index.js';

const FA_DIGITS = ['۰', '۱', '۲', '۳', '۴', '۵', '۶', '۷', '۸', '۹'];

/**
 * Converts Latin digits in a string to Persian digits.
 *
 * @param input - String or number containing Latin digits.
 * @returns String with Persian digits.
 */
export function toFaDigits(input: string | number): string {
  return String(input).replace(/[0-9]/g, (d) => FA_DIGITS[Number(d)]);
}

/** Approximate Toman -> USD conversion rate used for display only. */
const USD_RATE = 60_000;

/**
 * Formats a Toman amount into a localized currency string with Persian digits.
 *
 * @param amount - Amount in Toman.
 * @param currency - Target display currency.
 * @returns Formatted, grouped currency string.
 */
/**
 * Formats an amount (in `sourceCurrency`) into the user's display currency.
 */
export function formatMoney(
  amount: number,
  sourceCurrency: Currency = 'IRT',
  displayCurrency: Currency = 'IRT'
): string {
  const inIRT = sourceCurrency === 'USD' ? amount * USD_RATE : amount;
  if (displayCurrency === 'USD') {
    const usd = inIRT / USD_RATE;
    return `${usd.toLocaleString('en-US', { maximumFractionDigits: 1 })}`;
  }
  return `${toFaDigits(Math.round(inIRT).toLocaleString('en-US'))} تومان`;
}

/** Format a price in its native currency without conversion. */
export function formatNative(amount: number, currency: Currency): string {
  if (currency === 'USD') return `${amount.toLocaleString('en-US', { maximumFractionDigits: 2 })}`;
  return `${toFaDigits(Math.round(amount).toLocaleString('en-US'))} تومان`;
}

/**
 * Compact money formatting for chart axes and tight spaces.
 *
 * @param amount - Amount in Toman.
 * @returns Short string like "۱.۲م".
 */
export function formatMoneyShort(amount: number): string {
  if (amount >= 1_000_000) {
    return `${toFaDigits((amount / 1_000_000).toFixed(1))}م`;
  }
  if (amount >= 1_000) {
    return `${toFaDigits(Math.round(amount / 1_000))}ه`;
  }
  return toFaDigits(amount);
}

/** Accepted image MIME types for profile uploads. */
export const ACCEPTED_IMAGE_TYPES = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];

/**
 * Reads an image file, downscales it to fit within `max`×`max` while keeping
 * aspect ratio, and returns a compressed JPEG data URL safe to store in
 * LocalStorage.
 *
 * @param file - The user-selected image file.
 * @param max - Maximum width/height in pixels (defaults to 256).
 * @returns A promise resolving to a base64 data URL.
 */
export function resizeImageToDataUrl(file: File, max = 256): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error('failed to read file'));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error('failed to load image'));
      img.onload = () => {
        const scale = Math.min(1, max / Math.max(img.width, img.height));
        const w = Math.round(img.width * scale);
        const h = Math.round(img.height * scale);
        const canvas = document.createElement('canvas');
        canvas.width = w;
        canvas.height = h;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
          reject(new Error('canvas not supported'));
          return;
        }
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL('image/jpeg', 0.85));
      };
      img.src = String(reader.result);
    };
    reader.readAsDataURL(file);
  });
}

import type { Insight, Service } from '../types/index.js';
import { daysUntil, monthlyCost } from './dates.js';
import { toFaDigits } from './format.js';

/**
 * Computes Command Center insights purely from local service data.
 *
 * @param services - All managed services.
 * @returns Ordered list of actionable insights.
 */
export function computeInsights(services: Service[]): Insight[] {
  const active = services.filter((s) => s.active);
  const insights: Insight[] = [];

  // Soonest expiring domain / ssl / hosting.
  const expiring = active
    .filter((s) => ['domain', 'ssl', 'hosting'].includes(s.category))
    .map((s) => ({ s, d: daysUntil(s.nextRenewal) }))
    .filter((x) => x.d >= 0 && x.d <= 20)
    .sort((a, b) => a.d - b.d)[0];
  if (expiring) {
    insights.push({
      id: 'expiring',
      tone: 'warning',
      icon: '⚠️',
      text: `${expiring.s.name} تا ${toFaDigits(expiring.d)} روز دیگر منقضی می‌شود`,
    });
  }

  // Payments in the next 7 days.
  const soon = active.filter((s) => {
    const d = daysUntil(s.nextRenewal);
    return d >= 0 && d <= 7;
  });
  if (soon.length > 0) {
    insights.push({
      id: 'upcoming-pay',
      tone: 'info',
      icon: '📅',
      text: `${toFaDigits(soon.length)} پرداخت در ۷ روز آینده دارید`,
    });
  }

  // Spending trend (simulated comparison vs. last month using created dates).
  const monthly = active.reduce((sum, s) => sum + monthlyCost(s), 0);
  const newThisMonth = active.filter((s) => daysUntil(s.createdAt) >= -30);
  if (newThisMonth.length > 0 && monthly > 0) {
    const added = newThisMonth.reduce((sum, s) => sum + monthlyCost(s), 0);
    const pct = Math.round((added / monthly) * 100);
    if (pct > 0) {
      insights.push({
        id: 'trend',
        tone: 'danger',
        icon: '📈',
        text: `هزینه این ماه ${toFaDigits(Math.min(pct, 99))}٪ بیشتر از ماه قبل است`,
      });
    }
  }

  // Renewals this week.
  const thisWeek = active.filter((s) => {
    const d = daysUntil(s.nextRenewal);
    return d >= 0 && d <= 7;
  });
  insights.push({
    id: 'renew-week',
    tone: 'success',
    icon: '✅',
    text: `${toFaDigits(thisWeek.length)} سرویس این هفته تمدید می‌شوند`,
  });

  return insights;
}

