import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useSettings } from '../store/use-settings.js';
import styles from './auth-page.module.css';

type AuthMode = 'welcome' | 'phone' | 'email' | 'register';

/**
 * Authentication / onboarding screen. Frontend-only — stores the user name
 * locally. Structured to be replaced by real auth APIs later (phone OTP,
 * email/password, OAuth Google).
 *
 * @returns The auth page.
 */
export function AuthPage(): React.JSX.Element {
  const setUserName = useSettings((s) => s.setUserName);
  const setUserEmail = useSettings((s) => s.setUserEmail);
  const navigate = useNavigate();
  const [mode, setMode] = useState<AuthMode>('welcome');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [otp, setOtp] = useState('');
  const [otpSent, setOtpSent] = useState(false);

  const finish = () => {
    if (name.trim()) setUserName(name.trim());
    if (email.trim()) setUserEmail(email.trim());
    navigate('/');
  };

  if (mode === 'welcome') {
    return (
      <div className={styles.page}>
        <div className={styles.logoBox}>
          <span className={styles.logoText}>L</span>
        </div>
        <h1 className={styles.appName}>LifeOS</h1>
        <p className={styles.tagline}>مدیریت هوشمند سرویس‌ها و هزینه‌ها</p>

        <div className={styles.methods}>
          <button type="button" className={styles.google} onClick={() => { setName('کاربر جیمیل'); finish(); }}>
            <span className={styles.googleIcon}>G</span>
            ورود با Google
          </button>
          <button type="button" className={styles.methodBtn} onClick={() => setMode('phone')}>
            📱 ورود با شماره تلفن
          </button>
          <button type="button" className={styles.methodBtn} onClick={() => setMode('email')}>
            ✉️ ورود با ایمیل
          </button>
        </div>

        <button type="button" className={styles.register} onClick={() => setMode('register')}>
          حساب ندارید؟ ثبت نام کنید
        </button>
      </div>
    );
  }

  if (mode === 'phone') {
    return (
      <div className={styles.page}>
        <button type="button" className={styles.back} onClick={() => setMode('welcome')}>← بازگشت</button>
        <h2 className={styles.title}>ورود با شماره موبایل</h2>
        {!otpSent ? (
          <>
            <input className={styles.input} value={phone} onChange={(e) => setPhone(e.target.value)}
              placeholder="09XXXXXXXXX" inputMode="tel" />
            <input className={styles.input} value={name} onChange={(e) => setName(e.target.value)} placeholder="نام شما" />
            <button type="button" className={styles.primary} onClick={() => setOtpSent(true)}>ارسال کد تأیید</button>
          </>
        ) : (
          <>
            <p className={styles.hint}>کد ۶ رقمی ارسال شده به {phone} را وارد کنید</p>
            <input className={`${styles.input} ${styles.otpInput}`} value={otp} onChange={(e) => setOtp(e.target.value)}
              placeholder="_ _ _ _ _ _" inputMode="numeric" maxLength={6} />
            <button type="button" className={styles.primary} onClick={finish}>تأیید و ورود</button>
            <button type="button" className={styles.ghost} onClick={() => setOtpSent(false)}>ارسال مجدد کد</button>
          </>
        )}
      </div>
    );
  }

  if (mode === 'email') {
    return (
      <div className={styles.page}>
        <button type="button" className={styles.back} onClick={() => setMode('welcome')}>← بازگشت</button>
        <h2 className={styles.title}>ورود با ایمیل</h2>
        <input className={styles.input} value={name} onChange={(e) => setName(e.target.value)} placeholder="نام شما" />
        <input className={styles.input} value={email} onChange={(e) => setEmail(e.target.value)}
          placeholder="email@example.com" inputMode="email" />
        <input className={styles.input} value={pass} onChange={(e) => setPass(e.target.value)}
          placeholder="رمز عبور" type="password" />
        <button type="button" className={styles.primary} onClick={finish}>ورود</button>
      </div>
    );
  }

  // register
  return (
    <div className={styles.page}>
      <button type="button" className={styles.back} onClick={() => setMode('welcome')}>← بازگشت</button>
      <h2 className={styles.title}>ثبت نام</h2>
      <input className={styles.input} value={name} onChange={(e) => setName(e.target.value)} placeholder="نام و نام خانوادگی" />
      <input className={styles.input} value={email} onChange={(e) => setEmail(e.target.value)}
        placeholder="email@example.com" inputMode="email" />
      <input className={styles.input} value={phone} onChange={(e) => setPhone(e.target.value)}
        placeholder="شماره موبایل (اختیاری)" inputMode="tel" />
      <input className={styles.input} value={pass} onChange={(e) => setPass(e.target.value)}
        placeholder="رمز عبور" type="password" />
      <button type="button" className={styles.primary} onClick={finish}>ثبت نام</button>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useServices } from '../store/use-services.js';
import { AppHeader } from '../components/app-header.js';
import { HeroCard } from '../components/hero-card.js';
import { SectionHeader } from '../components/section-header.js';
import { Carousel } from '../components/carousel.js';
import { RenewalCard } from '../components/renewal-card.js';
import { ServiceCard } from '../components/service-card.js';
import { InsightCard } from '../components/insight-card.js';
import { ServiceMiniPopup } from '../components/service-mini-popup.js';
import { computeInsights } from '../lib/insights.js';
import { daysUntil } from '../lib/dates.js';
import type { Service } from '../types/index.js';

export function DashboardPage(): React.JSX.Element {
  const services = useServices((s) => s.services);
  const navigate = useNavigate();
  const [popup, setPopup] = useState<Service | null>(null);

  const upcoming = useMemo(
    () =>
      services
        .filter((s) => s.active && daysUntil(s.nextRenewal) >= 0)
        .sort((a, b) => daysUntil(a.nextRenewal) - daysUntil(b.nextRenewal))
        .slice(0, 8),
    [services]
  );
  const insights = useMemo(() => computeInsights(services), [services]);
  const all = useMemo(() => services.filter((s) => s.active), [services]);

  return (
    <div>
      <AppHeader />
      <HeroCard />

      <SectionHeader title="تمدیدهای نزدیک" action="مشاهده همه" onAction={() => navigate('/renewals')} />
      <Carousel>
        {upcoming.map((s) => (
          <RenewalCard key={s.id} service={s} onClick={() => setPopup(s)} />
        ))}
      </Carousel>

      <SectionHeader title="همه سرویس‌ها" action="مشاهده همه" onAction={() => navigate('/services')} />
      <Carousel>
        {all.map((s) => (
          <ServiceCard key={s.id} service={s} onClick={() => setPopup(s)} />
        ))}
      </Carousel>

      <SectionHeader title="مرکز کنترل" />
      <div>
        {insights.map((i) => (
          <InsightCard key={i.id} insight={i} />
        ))}
      </div>

      {popup ? <ServiceMiniPopup service={popup} onClose={() => setPopup(null)} /> : null}
    </div>
  );
}

import React, { useRef, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useServices } from '../store/use-services.js';
import { PageHeader } from '../components/page-header.js';
import { CATEGORY_META, CATEGORY_ORDER } from '../data/categories.js';
import { daysUntil } from '../lib/dates.js';
import { resizeImageToDataUrl, ACCEPTED_IMAGE_TYPES } from '../lib/image.js';
import type { BillingCycle, Currency, ServiceCategory } from '../types/index.js';
import styles from './add-service-page.module.css';

const COLORS = ['#A855F7', '#2FD0FF', '#63E8FF', '#34D399', '#F472B6', '#FBBF24', '#FB7185', '#6366F1'];

export function EditServicePage(): React.JSX.Element {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const service = useServices((s) => s.services.find((x) => x.id === id));
  const updateService = useServices((s) => s.updateService);
  const imgRef = useRef<HTMLInputElement>(null);

  const [name, setName] = useState(service?.name ?? '');
  const [plan, setPlan] = useState(service?.plan ?? '');
  const [price, setPrice] = useState(String(service?.price ?? ''));
  const [priceCurrency, setPriceCurrency] = useState<Currency>(service?.priceCurrency ?? 'IRT');
  const [category, setCategory] = useState<ServiceCategory>(service?.category ?? 'subscription');
  const [billingCycle, setBillingCycle] = useState<BillingCycle>(service?.billingCycle ?? 'monthly');
  const [days, setDays] = useState(String(service ? Math.max(daysUntil(service.nextRenewal), 0) : 30));
  const [color, setColor] = useState(service?.color ?? COLORS[0]);
  const [logoImage, setLogoImage] = useState<string | undefined>(service?.logoImage);

  if (!service) {
    return <div><PageHeader title="سرویس یافت نشد" back /><p className={styles.label}>این سرویس وجود ندارد.</p></div>;
  }

  const pickImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    e.target.value = '';
    if (!file || !ACCEPTED_IMAGE_TYPES.includes(file.type)) return;
    try { setLogoImage(await resizeImageToDataUrl(file, 256)); } catch { /* ignore */ }
  };

  const submit = () => {
    if (!name.trim() || !price) return;
    const next = new Date();
    next.setDate(next.getDate() + Number(days || 0));
    updateService(service.id, {
      name: name.trim(),
      plan: plan.trim() || CATEGORY_META[category].label,
      price: Number(price),
      priceCurrency,
      category, billingCycle,
      nextRenewal: next.toISOString(),
      color,
      logoText: service.logoText ?? name.trim().charAt(0).toUpperCase(),
      logoImage,
    });
    navigate(`/service/${service.id}`);
  };

  return (
    <div>
      <PageHeader title="ویرایش سرویس" back />
      <div className={styles.form}>

        <label className={styles.label}>لوگو</label>
        <div className={styles.logoRow}>
          <div className={styles.logoPreview} style={{ background: logoImage ? 'transparent' : color }}>
            {logoImage
              ? <img src={logoImage} alt="logo" className={styles.logoPreviewImg} />
              : <span>{name.charAt(0).toUpperCase() || service.name.charAt(0)}</span>}
          </div>
          <button type="button" className={styles.uploadBtn} onClick={() => imgRef.current?.click()}>📷 آپلود تصویر</button>
          {logoImage && <button type="button" className={styles.removeBtn} onClick={() => setLogoImage(undefined)}>✕</button>}
          <input ref={imgRef} type="file" accept=".jpg,.jpeg,.png,.webp" onChange={pickImage} style={{ display: 'none' }} />
        </div>

        <label className={styles.label}>نام سرویس</label>
        <input className={styles.input} value={name} onChange={(e) => setName(e.target.value)} placeholder="مثلاً Netflix" />

        <label className={styles.label}>پلن</label>
        <input className={styles.input} value={plan} onChange={(e) => setPlan(e.target.value)} placeholder="مثلاً پریمیوم" />

        <label className={styles.label}>دسته‌بندی</label>
        <div className={styles.chips}>
          {CATEGORY_ORDER.map((cat) => (
            <button key={cat} type="button"
              className={`${styles.chip} ${category === cat ? styles.activeChip : ''}`}
              onClick={() => setCategory(cat)}>
              {CATEGORY_META[cat].icon} {CATEGORY_META[cat].label}
            </button>
          ))}
        </div>

        <label className={styles.label}>قیمت</label>
        <div className={styles.priceRow}>
          <input className={`${styles.input} ${styles.priceInput}`} value={price}
            onChange={(e) => setPrice(e.target.value.replace(/\D/g, ''))}
            inputMode="numeric" />
          <div className={styles.currencyToggle}>
            {(['IRT', 'USD'] as Currency[]).map((c) => (
              <button key={c} type="button"
                className={`${styles.segBtn} ${priceCurrency === c ? styles.segActive : ''}`}
                onClick={() => setPriceCurrency(c)}>
                {c === 'IRT' ? 'تومان' : 'دلار'}
              </button>
            ))}
          </div>
        </div>

        <label className={styles.label}>دوره پرداخت</label>
        <div className={styles.segment}>
          <button type="button" className={`${styles.segBtn} ${billingCycle === 'monthly' ? styles.segActive : ''}`} onClick={() => setBillingCycle('monthly')}>ماهانه</button>
          <button type="button" className={`${styles.segBtn} ${billingCycle === 'yearly' ? styles.segActive : ''}`} onClick={() => setBillingCycle('yearly')}>سالانه</button>
        </div>

        <label className={styles.label}>تمدید بعدی (روز دیگر)</label>
        <input className={styles.input} value={days}
          onChange={(e) => setDays(e.target.value.replace(/\D/g, ''))} inputMode="numeric" />

        <label className={styles.label}>رنگ پس‌زمینه</label>
        <div className={styles.colors}>
          {COLORS.map((c) => (
            <button key={c} type="button"
              className={`${styles.swatch} ${color === c ? styles.activeSwatch : ''}`}
              style={{ background: c }} onClick={() => setColor(c)} aria-label={c} />
          ))}
        </div>

        <button className={styles.submit} type="button" onClick={submit}>ذخیره تغییرات</button>
      </div>
    </div>
  );
}

import React, { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { useServices } from '../store/use-services.js';
import { useSettings } from '../store/use-settings.js';
import { PageHeader } from '../components/page-header.js';
import { ServiceRow } from '../components/service-row.js';
import { monthlyCost } from '../lib/dates.js';
import { formatMoney } from '../lib/format.js';
import styles from './renewals-page.module.css';

/**
 * Lists recurring expenses (expense-category services) with a total summary.
 *
 * @returns The expenses page.
 */
export function ExpensesPage(): React.JSX.Element {
  const services = useServices((s) => s.services);
  const currency = useSettings((s) => s.currency);
  const navigate = useNavigate();

  const expenses = useMemo(
    () => services.filter((s) => s.category === 'expense'),
    [services]
  );
  const total = useMemo(
    () => expenses.filter((s) => s.active).reduce((sum, s) => sum + monthlyCost(s), 0),
    [expenses]
  );

  return (
    <div>
      <PageHeader title="هزینه‌ها" subtitle="هزینه‌های تکراری ماهانه" back />

      <div className={styles.group}>
        <p className={styles.groupTitle}>مجموع ماهانه: {formatMoney(total, 'IRT', currency)}</p>
        {expenses.map((s) => (
          <ServiceRow key={s.id} service={s} onClick={() => navigate(`/service/${s.id}`)} />
        ))}
        {expenses.length === 0 ? (
          <p style={{ textAlign: 'center', color: 'rgba(255,255,255,0.5)', padding: '40px 0' }}>
            هزینه‌ای ثبت نشده است
          </p>
        ) : null}
      </div>
    </div>
  );
}

