import React, { useRef } from 'react';
import { useServices } from '../store/use-services.js';
import { useSettings } from '../store/use-settings.js';
import { PageHeader } from '../components/page-header.js';
import type { Currency, Language, Service } from '../types/index.js';
import styles from './settings-page.module.css';

/**
 * Settings screen: currency, language, data export/import, and reset. Profile
 * management lives in the avatar popover, not here.
 *
 * @returns The settings page.
 */
export function SettingsPage(): React.JSX.Element {
  const { currency, language, setCurrency, setLanguage } = useSettings();
  const services = useServices((s) => s.services);
  const replaceAll = useServices((s) => s.replaceAll);
  const reset = useServices((s) => s.reset);
  const fileRef = useRef<HTMLInputElement>(null);

  /** Downloads all services as a JSON file. */
  const exportData = () => {
    const blob = new Blob([JSON.stringify(services, null, 2)], {
      type: 'application/json',
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'lifeos-data.json';
    a.click();
    URL.revokeObjectURL(url);
  };

  /** Reads a selected JSON file and replaces all services. */
  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const parsed = JSON.parse(String(reader.result)) as Service[];
        if (Array.isArray(parsed)) replaceAll(parsed);
      } catch {
        // ignore malformed files
      }
    };
    reader.readAsText(file);
  };

  return (
    <div>
      <PageHeader title="تنظیمات" subtitle="شخصی‌سازی LifeOS" back />

      <div className={styles.section}>
        <p className={styles.sectionTitle}>واحد پول</p>
        <div className={styles.segment}>
          {(['IRT', 'USD'] as Currency[]).map((c) => (
            <button
              key={c}
              type="button"
              className={`${styles.segBtn} ${currency === c ? styles.segActive : ''}`}
              onClick={() => setCurrency(c)}
            >
              {c === 'IRT' ? 'تومان' : 'دلار'}
            </button>
          ))}
        </div>
      </div>

      <div className={styles.section}>
        <p className={styles.sectionTitle}>زبان</p>
        <div className={styles.segment}>
          {(['fa', 'en'] as Language[]).map((l) => (
            <button
              key={l}
              type="button"
              className={`${styles.segBtn} ${language === l ? styles.segActive : ''}`}
              onClick={() => setLanguage(l)}
            >
              {l === 'fa' ? 'فارسی' : 'English'}
            </button>
          ))}
        </div>
      </div>

      <div className={styles.section}>
        <p className={styles.sectionTitle}>داده‌ها</p>
        <button className={styles.action} type="button" onClick={exportData}>
          📤 خروجی گرفتن از داده‌ها
        </button>
        <button className={styles.action} type="button" onClick={() => fileRef.current?.click()}>
          📥 وارد کردن داده‌ها
        </button>
        <input
          ref={fileRef}
          type="file"
          accept="application/json"
          onChange={importData}
          style={{ display: 'none' }}
        />
        <button
          className={`${styles.action} ${styles.danger}`}
          type="button"
          onClick={() => {
            if (confirm('بازنشانی برنامه؟ همه داده‌ها به حالت اولیه برمی‌گردند.')) reset();
          }}
        >
          ♻️ بازنشانی برنامه
        </button>
      </div>

      <p className={styles.version}>LifeOS · نسخه ۱.۰.۰</p>
    </div>
  );
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Service } from '../types/index.js';
import { SEED_SERVICES } from '../data/seed.js';

/**
 * Shape of the services store.
 */
interface ServicesState {
  services: Service[];
  /** Add a new service (id + createdAt are generated if missing). */
  addService: (
    input: Omit<Service, 'id' | 'createdAt'> & Partial<Pick<Service, 'id' | 'createdAt'>>
  ) => void;
  /** Update an existing service by id. */
  updateService: (id: string, patch: Partial<Service>) => void;
  /** Remove a service by id. */
  removeService: (id: string) => void;
  /** Toggle the active flag of a service. */
  toggleActive: (id: string) => void;
  /** Replace the entire collection (used by data import). */
  replaceAll: (services: Service[]) => void;
  /** Restore the seed dataset. */
  reset: () => void;
}

/**
 * Generates a reasonably unique id for a new service.
 */
function genId(): string {
  return `svc-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
}

/**
 * Persisted Zustand store holding all managed services in LocalStorage.
 */
export const useServices = create<ServicesState>()(
  persist(
    (set) => ({
      services: SEED_SERVICES,
      addService: (input) =>
        set((state) => ({
          services: [
            {
              ...input,
              id: input.id ?? genId(),
              createdAt: input.createdAt ?? new Date().toISOString(),
            },
            ...state.services,
          ],
        })),
      updateService: (id, patch) =>
        set((state) => ({
          services: state.services.map((s) => (s.id === id ? { ...s, ...patch } : s)),
        })),
      removeService: (id) =>
        set((state) => ({ services: state.services.filter((s) => s.id !== id) })),
      toggleActive: (id) =>
        set((state) => ({
          services: state.services.map((s) =>
            s.id === id ? { ...s, active: !s.active } : s
          ),
        })),
      replaceAll: (services) => set({ services }),
      reset: () => set({ services: SEED_SERVICES }),
    }),
    { name: 'lifeos-services' }
  )
);

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Settings } from '../types/index.js';

/**
 * Shape of the settings store.
 */
interface SettingsState extends Settings {
  setCurrency: (currency: Settings['currency']) => void;
  setLanguage: (language: Settings['language']) => void;
  setUserName: (userName: string) => void;
  setUserEmail: (userEmail: string) => void;
  /** Set or clear the profile picture (pass undefined to remove). */
  setAvatarImage: (avatarImage: string | undefined) => void;
}

/**
 * Persisted Zustand store holding user preferences in LocalStorage.
 */
export const useSettings = create<SettingsState>()(
  persist(
    (set) => ({
      currency: 'IRT',
      language: 'fa',
      userName: 'علی',
      userEmail: 'ali@lifeos.app',
      avatarImage: undefined,
      setCurrency: (currency) => set({ currency }),
      setLanguage: (language) => set({ language }),
      setUserName: (userName) => set({ userName }),
      setUserEmail: (userEmail) => set({ userEmail }),
      setAvatarImage: (avatarImage) => set({ avatarImage }),
    }),
    { name: 'lifeos-settings' }
  )
);

